INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 2, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 0.0, "アヤネ", 24001, 102301, 0.0, 10046, 24, 0.0, 401);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 2.21, "アヤネ", 24002, 102301, 0.0, 10046, 24, 0.0, 402);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 2, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 0.0, "アヤネ", 24003, 102301, 0.0, 10046, 24, 0.0, 403);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 1, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 1.99, "アサヒ", 24004, 192201, 0.0, 10046, 24, 0.0, 701);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 2.21, "アサヒ", 24005, 192201, 0.0, 10046, 24, 0.0, 702);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 1, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 3.33, "アサヒ", 24006, 192201, 0.0, 10046, 24, 0.0, 703);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 2, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 0.0, "部員３", 24007, 192301, 0.0, 10046, 24, 0.0, 801);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 2.68, "部員３", 24008, 192301, 0.0, 10046, 24, 0.0, 802);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 2, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 0.0, "部員３", 24009, 192301, 0.0, 10046, 24, 0.0, 803);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 1, "やった！", 0.0, "", 24010, 192501, 0.0, 10046, 24, 0.0, 501);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 1, "勝ったよ！", 0.0, "", 24011, 192501, 0.0, 10046, 24, 0.0, 502);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 1, "いい調子！", 0.0, "", 24012, 192501, 0.0, 10046, 24, 0.0, 503);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 6, "2030/12/17 14:59:59", 2, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 5.33, "ミサト", 24013, 113501, 0.0, 10046, 24, 0.0, 111);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 6.85, "ミサト", 24014, 113501, 0.0, 10046, 24, 0.0, 112);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 3.0, "ミサト", 24015, 113501, 0.0, 10046, 24, 0.0, 113);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 6.11, "ダイチ", 24016, 192401, 0.0, 10046, 24, 0.0, 611);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 6.75, "ダイチ", 24017, 192401, 0.0, 10046, 24, 0.0, 612);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 2, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 0.0, "ダイチ", 24018, 192401, 0.0, 10046, 24, 0.0, 613);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 1, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 4.52, "ハツネ", 24019, 113401, 0.0, 10046, 24, 0.0, 211);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 1, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 3.89, "ハツネ", 24020, 113401, 0.0, 10046, 24, 0.0, 212);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 13.49, "ハツネ", 24021, 113401, 0.0, 10046, 24, 0.0, 213);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 3.17, "カヤ", 24022, 106501, 0.0, 10046, 24, 0.0, 311);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 4.42, "カヤ", 24023, 106501, 0.0, 10046, 24, 0.0, 312);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 6, "2030/12/17 14:59:59", 1, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 2.89, "カヤ", 24024, 106501, 0.0, 10046, 24, 0.0, 313);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 4, "2030/12/17 14:59:59", 3, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 3.71, "アヤネ", 24025, 102301, 0.0, 10046, 24, 0.0, 421);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 1, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 5.1, "アサヒ", 24026, 192201, 0.0, 10046, 24, 0.0, 721);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 3, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 4.34, "部員３", 24027, 192301, 0.0, 10046, 24, 0.0, 821);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 1, "いい勝負だったよ\nまたやろうね", 0.0, "", 24028, 192501, 0.0, 10046, 24, 0.0, 521);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 5.62, "ミサト", 24029, 113501, -360.0, 10046, 24, 0.0, 101);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 9.58, "ミサト", 24030, 113501, -360.0, 10046, 24, 0.0, 102);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 2, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 0.0, "ミサト", 24031, 113501, -360.0, 10046, 24, 0.0, 103);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 2, "2030/12/17 14:59:59", 1, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 9.13, "ミサト", 24032, 113501, -360.0, 10046, 24, 0.0, 104);
INSERT INTO `v1_0ee98c2e63263f80c341a62d8903cace6cb2eca1f802ea0dbf546118ccb0e3c5` VALUES ("2020/07/31 12:00:00", 1, "2030/12/17 14:59:59", 2, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 8.27, "ミサト", 24033, 113501, -360.0, 10046, 24, 0.0, 105);
